using UnityEngine;
using UnityEngine.Purchasing;
using System;

public class PlayerStats : MonoBehaviour
{
    [Header("Core Stats (Public)")]
    public int level = 1;
    public int maxHealth = 100;
    public int currentHealth = 100;

    [Header("Combat (Public)")]
    public int baseDamage = 10;
    public float critChance = 0.1f;
    public float critMultiplier = 2.0f;
    public float damageMultiplier = 1.0f;

    [Header("Economy (Public)")]
    public int softCurrency = 0;
    public int premiumCurrency = 0;

    [Header("Progression (Public)")]
    public int damageUpgradeLevel = 0;
    public int healthUpgradeLevel = 0;
    public int shopDiscountLevel = 0;

    [Header("Tuning (Public)")]
    public int healthPerUpgrade = 25;
    public int damagePerUpgrade = 3;
    public float discountPerLevel = 0.02f;
    public float maxDiscount = 0.30f;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;

    void Awake()
    {
        currentHealth = Mathf.Clamp(currentHealth, 0, GetMaxHealthCalculated());
        RaiseHealthChanged();
        RaiseCurrencyChanged();
    }

    public int GetMaxHealthCalculated()
    {
        return Mathf.Max(1, maxHealth + healthUpgradeLevel * healthPerUpgrade);
    }

    public int GetDamageCalculated(System.Random rng = null)
    {
        int dmg = Mathf.Max(0, baseDamage + damageUpgradeLevel * damagePerUpgrade);
        float mult = Mathf.Max(0f, damageMultiplier);
        float final = dmg * mult;

        bool crit = false;
        if (rng != null)
        {
            crit = rng.NextDouble() < Mathf.Clamp01(critChance);
        }
        else
        {
            crit = UnityEngine.Random.value < Mathf.Clamp01(critChance);
        }

        if (crit) final *= Mathf.Max(1f, critMultiplier);

        return Mathf.Max(0, Mathf.RoundToInt(final));
    }

    public int ApplyDamage(int incomingDamage)
    {
        int dmg = Mathf.Max(0, incomingDamage);
        currentHealth = Mathf.Clamp(currentHealth - dmg, 0, GetMaxHealthCalculated());
        RaiseHealthChanged();
        return dmg;
    }

    public int Heal(int amount)
    {
        int heal = Mathf.Max(0, amount);
        int before = currentHealth;
        currentHealth = Mathf.Clamp(currentHealth + heal, 0, GetMaxHealthCalculated());
        RaiseHealthChanged();
        return currentHealth - before;
    }

    public void AddSoftCurrency(int amount)
    {
        softCurrency = Mathf.Max(0, softCurrency + amount);
        RaiseCurrencyChanged();
    }

    public void AddPremiumCurrency(int amount)
    {
        premiumCurrency = Mathf.Max(0, premiumCurrency + amount);
        RaiseCurrencyChanged();
    }

    public bool SpendSoftCurrency(int amount)
    {
        int cost = Mathf.Max(0, amount);
        if (softCurrency < cost) return false;
        softCurrency -= cost;
        RaiseCurrencyChanged();
        return true;
    }

    public bool SpendPremiumCurrency(int amount)
    {
        int cost = Mathf.Max(0, amount);
        if (premiumCurrency < cost) return false;
        premiumCurrency -= cost;
        RaiseCurrencyChanged();
        return true;
    }

    public float GetDiscountFactor()
    {
        float discount = Mathf.Clamp(shopDiscountLevel * discountPerLevel, 0f, maxDiscount);
        return Mathf.Clamp01(1f - discount);
    }

    void RaiseHealthChanged() => OnHealthChanged?.Invoke(currentHealth, GetMaxHealthCalculated());
    void RaiseCurrencyChanged() => OnCurrencyChanged?.Invoke(softCurrency, premiumCurrency);
}

public enum CurrencyType
{
    Soft,
    Premium
}

[Serializable]
public class ShopItemDefinition
{
    public string id;
    public string displayName;

    public CurrencyType currencyType = CurrencyType.Soft;

    [Header("Base Price + Growth")]
    public int basePrice = 100;
    public float priceGrowth = 1.15f;

    [Header("Purchase Limits")]
    public bool unlimited = true;
    public int maxPurchases = 1;

    [Header("Effects")]
    public int addSoftCurrency = 0;
    public int addPremiumCurrency = 0;

    public int addMaxHealthUpgrades = 0;
    public int addDamageUpgrades = 0;
    public int addDiscountUpgrades = 0;

    public int healAmount = 0;

    public int purchases = 0;

    public int GetPrice(PlayerStats stats)
    {
        int p = Mathf.Max(0, basePrice);
        float growth = Mathf.Max(1f, priceGrowth);
        int n = Mathf.Max(0, purchases);
        float raw = p * Mathf.Pow(growth, n);
        float discounted = raw * (stats != null ? stats.GetDiscountFactor() : 1f);
        return Mathf.Max(0, Mathf.RoundToInt(discounted));
    }

    public bool CanPurchase()
    {
        if (unlimited) return true;
        return purchases < Mathf.Max(0, maxPurchases);
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerStats playerStats;
    public ShopItemDefinition[] items;

    public event Action<ShopItemDefinition> OnPurchased;
    public event Action<ShopItemDefinition> OnPurchaseFailed;

    public ShopItemDefinition GetItem(string id)
    {
        if (items == null) return null;
        for (int i = 0; i < items.Length; i++)
        {
            if (items[i] != null && items[i].id == id) return items[i];
        }
        return null;
    }

    public int GetPrice(string id)
    {
        var item = GetItem(id);
        if (item == null) return -1;
        return item.GetPrice(playerStats);
    }

    public bool TryPurchase(string id)
    {
        var item = GetItem(id);
        if (item == null || playerStats == null)
        {
            OnPurchaseFailed?.Invoke(item);
            return false;
        }

        if (!item.CanPurchase())
        {
            OnPurchaseFailed?.Invoke(item);
            return false;
        }

        int price = item.GetPrice(playerStats);
        bool paid = false;

        switch (item.currencyType)
        {
            case CurrencyType.Soft:
                paid = playerStats.SpendSoftCurrency(price);
                break;
            case CurrencyType.Premium:
                paid = playerStats.SpendPremiumCurrency(price);
                break;
        }

        if (!paid)
        {
            OnPurchaseFailed?.Invoke(item);
            return false;
        }

        ApplyItemEffects(item);
        item.purchases = Mathf.Max(0, item.purchases + 1);

        OnPurchased?.Invoke(item);
        return true;
    }

    void ApplyItemEffects(ShopItemDefinition item)
    {
        if (item == null || playerStats == null) return;

        if (item.addSoftCurrency != 0) playerStats.AddSoftCurrency(item.addSoftCurrency);
        if (item.addPremiumCurrency != 0) playerStats.AddPremiumCurrency(item.addPremiumCurrency);

        if (item.addMaxHealthUpgrades != 0)
        {
            playerStats.healthUpgradeLevel = Mathf.Max(0, playerStats.healthUpgradeLevel + item.addMaxHealthUpgrades);
            playerStats.currentHealth = Mathf.Clamp(playerStats.currentHealth, 0, playerStats.GetMaxHealthCalculated());
        }

        if (item.addDamageUpgrades != 0)
        {
            playerStats.damageUpgradeLevel = Mathf.Max(0, playerStats.damageUpgradeLevel + item.addDamageUpgrades);
        }

        if (item.addDiscountUpgrades != 0)
        {
            playerStats.shopDiscountLevel = Mathf.Max(0, playerStats.shopDiscountLevel + item.addDiscountUpgrades);
        }

        if (item.healAmount > 0)
        {
            playerStats.Heal(item.healAmount);
        }
    }
}

public class CombatExample : MonoBehaviour
{
    public PlayerStats playerStats;

    [Header("Enemy (Public)")]
    public int enemyHealth = 50;

    public event Action<int> OnEnemyDamaged;
    public event Action OnEnemyDefeated;

    public int AttackEnemy()
    {
        if (playerStats == null) return 0;
        if (enemyHealth <= 0) return 0;

        int dmg = playerStats.GetDamageCalculated();
        enemyHealth = Mathf.Max(0, enemyHealth - dmg);

        OnEnemyDamaged?.Invoke(dmg);
        if (enemyHealth == 0) OnEnemyDefeated?.Invoke();

        return dmg;
    }
}

public class IAPManager : MonoBehaviour, IStoreListener
{
    public PlayerStats playerStats;

    [Header("Product IDs (Public)")]
    public string premiumSmallProductId = "premium_small";
    public string premiumMediumProductId = "premium_medium";
    public string premiumLargeProductId = "premium_large";

    [Header("Rewards (Public)")]
    public int premiumSmallAmount = 100;
    public int premiumMediumAmount = 550;
    public int premiumLargeAmount = 1200;

    IStoreController controller;
    IExtensionProvider extensions;

    public event Action<string> OnIAPPurchaseSucceeded;
    public event Action<string, string> OnIAPPurchaseFailed;

    void Start()
    {
        InitializePurchasing();
    }

    public void InitializePurchasing()
    {
        if (controller != null) return;

        var builder = ConfigurationBuilder.Instance(StandardPurchasingModule.Instance());
        builder.AddProduct(premiumSmallProductId, ProductType.Consumable);
        builder.AddProduct(premiumMediumProductId, ProductType.Consumable);
        builder.AddProduct(premiumLargeProductId, ProductType.Consumable);

        UnityPurchasing.Initialize(this, builder);
    }

    public void BuyPremiumSmall() => BuyProduct(premiumSmallProductId);
    public void BuyPremiumMedium() => BuyProduct(premiumMediumProductId);
    public void BuyPremiumLarge() => BuyProduct(premiumLargeProductId);

    public void BuyProduct(string productId)
    {
        if (controller == null)
        {
            OnIAPPurchaseFailed?.Invoke(productId, "IAP not initialized");
            return;
        }

        var product = controller.products.WithID(productId);
        if (product == null || !product.availableToPurchase)
        {
            OnIAPPurchaseFailed?.Invoke(productId, "Product not available");
            return;
        }

        controller.InitiatePurchase(product);
    }

    public void OnInitialized(IStoreController controller, IExtensionProvider extensions)
    {
        this.controller = controller;
        this.extensions = extensions;
    }

    public void OnInitializeFailed(InitializationFailureReason error)
    {
        OnIAPPurchaseFailed?.Invoke("init", error.ToString());
    }

#if UNITY_PURCHASING_4_OR_NEWER
    public void OnInitializeFailed(InitializationFailureReason error, string message)
    {
        OnIAPPurchaseFailed?.Invoke("init", error + (string.IsNullOrEmpty(message) ? "" : (": " + message)));
    }
#endif

    public PurchaseProcessingResult ProcessPurchase(PurchaseEventArgs e)
    {
        if (playerStats == null)
        {
            OnIAPPurchaseFailed?.Invoke(e.purchasedProduct.definition.id, "Missing PlayerStats");
            return PurchaseProcessingResult.Complete;
        }

        string id = e.purchasedProduct.definition.id;

        if (id == premiumSmallProductId) playerStats.AddPremiumCurrency(premiumSmallAmount);
        else if (id == premiumMediumProductId) playerStats.AddPremiumCurrency(premiumMediumAmount);
        else if (id == premiumLargeProductId) playerStats.AddPremiumCurrency(premiumLargeAmount);

        OnIAPPurchaseSucceeded?.Invoke(id);
        return PurchaseProcessingResult.Complete;
    }

    public void OnPurchaseFailed(Product product, PurchaseFailureReason failureReason)
    {
        OnIAPPurchaseFailed?.Invoke(product != null ? product.definition.id : "unknown", failureReason.ToString());
    }
}